#include <stdio.h>
#include <stdlib.h>

// Structure to represent a state in the NFA
typedef struct State {
  int id;
  int *transitions;
  int accepting;
} State;

// Structure to represent the NFA
typedef struct NFA {
  int numStates;
  State *states;
} NFA;

// Structure to represent the DFA
typedef struct DFA {
  int numStates;
  State *states;
} DFA;

// Function to create a new DFA from a given NFA
DFA *subsetConstruction(NFA *nfa) {
  DFA *dfa = (DFA *)malloc(sizeof(DFA));
  dfa->numStates = 1 << nfa->numStates;
  dfa->states = (State *)malloc(dfa->numStates * sizeof(State));

  // Create new states in the DFA
  for (int i = 0; i < nfa->numStates; i++) {
    dfa->states[i].id = i;
    dfa->states[i].transitions = (int *)malloc(nfa->numStates * sizeof(int));
    dfa->states[i].accepting = nfa->states[i].accepting;
  }

  // Create new transitions in the DFA
  for (int i = 0; i < nfa->numStates; i++) {
    for (int j = 0; j < nfa->numStates; j++) {
      dfa->states[i].transitions[j] = nfa->states[i].transitions[j];
    }
  }

  return dfa;
}

int main() {
  NFA *nfa = (NFA *)malloc(sizeof(NFA));
  nfa->numStates = 2;
  nfa->states = (State *)malloc(nfa->numStates * sizeof(State));

  // Create states in the NFA
  nfa->states[0].id = 0;
  nfa->states[0].transitions = (int *)malloc(nfa->numStates * sizeof(int));
  nfa->states[0].accepting = 0;
  nfa->states[1].id = 1;
  nfa->states[1].transitions = (int *)malloc(nfa->numStates * sizeof(int));
  nfa->states[1].accepting = 1;

  // Create transitions in the NFA
  nfa->states[0].transitions[0] = 1;
  nfa->states[0].transitions[1] = 0;
  nfa->states[1].transitions[0] = 0;
  nfa->states[1].transitions[1] = 1;

  // Create DFA from NFA
  DFA *dfa = subsetConstruction(nfa);

  // Print DFA
  printf("DFA:\n");
  for (int i = 0; i < dfa->numStates; i++) {
    printf("State %d: ", dfa->states[i].id);
    for (int j = 0; j < dfa->numStates; j++) {
      printf("%d ", dfa->states[i].transitions[j]);
    }
    printf("\n");
  }

  return 0;
}
